'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes } from 'react'
import styles from './code.module.css'

export interface CodeProps extends HTMLAttributes<HTMLElement> {
  size?: 'sm' | 'md'
}

export function Code({ size = 'md', className, children, ...props }: CodeProps) {
  return (
    <code
      data-size={size}
      className={cn(styles['code'], className as string | undefined)}
      {...props}
    >
      {children}
    </code>
  )
}

@layer cascivo.component {
  .code {
    font-family: var(--cascivo-font-mono);
    color: var(--cascivo-color-text);
    background-color: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-indicator);
    padding-block: 0.0625rem;
    padding-inline: var(--cascivo-space-1);
    white-space: nowrap;

    &[data-size='sm'] {
      font-size: var(--cascivo-text-xs);
    }

    &[data-size='md'] {
      font-size: var(--cascivo-text-sm);
    }
  }
}
